ALTER TABLE public.company_job_profiles
  ADD COLUMN IF NOT EXISTS salary_note text,
  ADD COLUMN IF NOT EXISTS starting_salary_min bigint,
  ADD COLUMN IF NOT EXISTS starting_salary_max bigint,
  ADD COLUMN IF NOT EXISTS starting_salary_currency text,
  ADD COLUMN IF NOT EXISTS starting_salary_note text,
  ADD COLUMN IF NOT EXISTS average_annual_salary bigint,
  ADD COLUMN IF NOT EXISTS average_annual_salary_note text,
  ADD COLUMN IF NOT EXISTS average_tenure_years numeric(4,1),
  ADD COLUMN IF NOT EXISTS salary_last_checked_at date,
  ADD COLUMN IF NOT EXISTS salary_data_quality_notes text[] DEFAULT '{}',
  ADD COLUMN IF NOT EXISTS salary_source_links jsonb DEFAULT '[]'::jsonb;

UPDATE public.company_job_profiles AS profiles
SET salary_note = salary_data.salary_note,
    starting_salary_min = salary_data.starting_salary_min,
    starting_salary_max = salary_data.starting_salary_max,
    starting_salary_currency = salary_data.starting_salary_currency,
    starting_salary_note = salary_data.starting_salary_note,
    average_annual_salary = salary_data.average_annual_salary,
    average_annual_salary_note = salary_data.average_annual_salary_note,
    average_tenure_years = salary_data.average_tenure_years,
    salary_last_checked_at = salary_data.salary_last_checked_at,
    salary_data_quality_notes = salary_data.salary_data_quality_notes,
    salary_source_links = salary_data.salary_source_links,
